import React, { useState, useEffect, lazy } from 'react'
import { useParams } from 'react-router';
import { API_MOVIE, API_KEY, POSTER_PATH, WIDTH_ORIGINAL, WIDTH_500, count_runtime, avg, currency } from '../constant';
import { LazyLoadImage } from 'react-lazy-load-image-component';
import { retry } from '../utils/CommonFunctions';
import axios from 'axios';
import frame1 from '../resources/Frame1.png'
import frame2 from '../resources/Frame2.png'
import { FiArrowRight } from 'react-icons/fi';
const RowList = lazy(() => retry(() => import('./RowList')));
const CastList = lazy(() => retry(() => import('./CastList')));
const Keyword = lazy(() => retry(() => import('./Keyword')));
const Review = lazy(() => retry(() => import('./Review')));
const ExternalId = lazy(() => retry(() => import('./ExternalId')));
const Video = lazy(() => retry(() => import('./Video')));

const Movie = () => {

  const id = useParams().id;
  const [data, setData] = useState([]);

  useEffect(() => {
    const getData = async () => {
      axios.get(API_MOVIE + id + '?api_key=' + API_KEY)
        .then((data) => {
          setData(data.data);
        })
        .catch((error) => {
          console.error(error);
        })
    }

    getData();
  }, [id]);

  return (
    <>
      <LazyLoadImage className="img-backdrop" src={POSTER_PATH + WIDTH_ORIGINAL + data.backdrop_path} effect="opacity" alt={data.title} onError={(e) => { e.target.onerror = null; e.target.src = frame2 }} />
      <div className="container">
        <div className="row">
          <div className="col-12 col-md-2">
            <LazyLoadImage className="img-poster" src={POSTER_PATH + WIDTH_500 + data.poster_path} effect="opacity" alt={data.title} onError={(e) => { e.target.onerror = null; e.target.src = frame1 }} />
            {data.homepage ? <div><a href={data.homepage} target="_blank" rel="noreferrer">Homepage <FiArrowRight className="ms-2 mb-1" /></a></div> : null}
            <div className="bebasFont hide-md mt-3 mb-3 text-break">{data.title}</div>
            <div>
              <div><ExternalId id={id} name='movie' /></div>
              <div>{data.status ? <><div className="text-bold">Status</div><div>{data.status}</div></> : null}</div>
              <div>{data.original_language ? <><div className="mt-4 text-bold">Language</div><div>{data.original_language}</div></> : null}</div>
              <div>{data.revenue !== 0 ? <><div className="mt-4 text-bold">Revenue</div><div>{currency(data.revenue)}</div></> : null}</div>
              <div>{data.budget !== 0 ? <><div className="mt-4 text-bold">Budget</div><div>{currency(data.budget)}</div></> : null}</div>
            </div>
            <Keyword id={id} name='movie' />
          </div>
          <div className="col-12 col-md-10 mt-3">
            <div className="bebasFont hide-sm text-break">{data.title}</div>
            <div>
              {data['genres'] ? data['genres'].map((dataGenre, index) => (
                <span className="genre" key={index}>{dataGenre.name}</span>
              )) : null}
            </div>
            <div>{`${data.release_date}`.substring(0, 4)} &#8212; {count_runtime(data.runtime)}</div>
            <div>{data.vote_average ? avg(data.vote_average) : 'Unrated'} <span className="stars" style={{'--rating': data.vote_average ? avg(data.vote_average) : 'Unrated'}} aria-label="Rating of this product is 2.3 out of 5."></span></div>
            <div className="mt-4 text-bold">{data.tagline ? '"' + data.tagline + '"' : null}</div>
            <div>{data.overview ? data.overview : null}</div>
            <Video id={id} name='movie' />
            <CastList id={id} name='movie' />
            <Review id={id} name='movie' />
          </div>
        </div>
        <RowList name='recommendationMovie' id={id} />
        <RowList name='similarMovie' id={id} />
      </div>
    </>
  )
}

export default Movie
